import { useMemo } from "react";
import { computeField } from "../root/hooks/use-api/auxiliary-functions/compute-field.js";
export function useSortFn(sort) {
    return useMemo(() => {
        if (!sort)
            return null;
        if (typeof sort === "function")
            return sort;
        if (sort.length === 0)
            return null;
        const sortFn = (left, right) => {
            for (const { dim, descending } of sort) {
                if (typeof dim === "function") {
                    return descending ? dim(right, left) : dim(left, right);
                }
                const field = dim.field ?? dim.id;
                if (!field)
                    continue;
                const x = computeField(left.kind === "leaf" ? field : (dim?.id ?? field), left);
                const y = computeField(right.kind === "leaf" ? field : (dim?.id ?? field), right);
                if (x < y)
                    return descending ? 1 : -1;
                if (x > y)
                    return descending ? -1 : 1;
            }
            return 0;
        };
        return sortFn;
    }, [sort]);
}
